/* adm-master-owner-sql-oracle.xml - selectOwnerCount */
SELECT 	COUNT(1)  
FROM TADMIN_MST_OW



		AND #{SEARCH_CONDITION}

/* adm-master-owner-sql-oracle.xml - selectOwner */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , OWKEY , OWNM , REGNO , BIZTYPE , BIZCTG , ADDRID , ZIPCD , ADDR1 , ADDR2 , TEL1 , TEL2 , FAX , CONTACT , CEO , UDF1 , UDF3 , MASTERUPDATEIMPOS , CARTYPE , DELYN , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY FROM TADMIN_MST_OW
AND #{SEARCH_CONDITION}
ORDER BY UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.delete:
/* adm-master-owner-sql-oracle.xml - deleteTAdminMstOw */
UPDATE TADMIN_MST_OW
SET
	  DELYN = 'Y'
	, CLOSDATE = #{closdate}
	, UPDATEURKEY = #{surkey}
	, UPDATEDATE = #{sysdate}
WHERE	OWKEY = #{owkey}

