mapper.update:
		/* adm-master-owner-sql-oracle.xml - updateTAdminMstOw */
		UPDATE 	TADMIN_MST_OW
		   SET	UPDATEURKEY  		= #{surkey}
				,UPDATEDATE   		= #{sysdate}
				,TEL2         		= #{tel2}
				,TEL1         		= #{tel1}
				,OWNM       		= #{ownm}
				,REGNO       		= #{regno}
		        ,BIZTYPE   			= #{biztype}
		        ,BIZCTG				= #{bizctg}
				,FAX          		= #{fax}
				,CONTACT      		= #{contact}
				,CEO          		= #{ceo}
				,DIMENSIONUOM		= #{dimensionuom}
				,WEIGHTUOM			= #{weightuom}
				,UDF1				= #{udf1}
				,UDF2				= #{udf2}
				,UDF3				= #{udf3}
				,BOXTYPE			= #{boxtype}
				,LAKEY				= #{lakey}
	            ,CURRTYPE			= #{currtype}
	            ,BARCODETYPE		= #{barcodetype}
	            ,DELSTTVRFTYPE		= #{delsttvrftype}
	            ,ALWMXDYN			= #{alwmxdyn}
	            ,EMAIL				= #{email}
	            ,WEBURL				= #{weburl}
	            ,UOMTYPE			= #{uomtype}
	            ,LOGGRPCD			= #{loggrpcd}
	            ,CUSTTYPE			= #{custtype}	 
	            ,ADDRID				= #{addrid}
